import { LoopAgentScreen } from "@/components/loop-agent/loop-agent-screen";

export default function LoopAgentPage() {
  return <LoopAgentScreen />;
}

import { handleLoopAgentRequest } from "@/lib/loop-agent/runtime";

export const runtime = "nodejs";

export function POST(request: Request) {
  return handleLoopAgentRequest(request);
}

import { Badge } from "@/components/ui/badge";

import { getLoopAgentRuntimeState } from "@/lib/loop-agent/runtime";
import { runSupportTriageLoop } from "@/lib/loop-agent/support-triage";
import { LoopAgentWorkspace } from "@/components/loop-agent/loop-agent-workspace";

export function LoopAgentScreen() {
  const runtimeState = getLoopAgentRuntimeState();
  const triage = runSupportTriageLoop();

  return (
    <main className="min-h-svh bg-background text-foreground">
      <div className="mx-auto flex w-full max-w-7xl flex-col gap-6 px-4 py-6 md:px-6">
        <header className="grid gap-4 border border-foreground/10 bg-background px-4 py-5 md:grid-cols-[minmax(0,1fr)_auto] md:items-end">
          <div className="space-y-2">
            <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
              Demo / Loop Agent
            </p>
            <h1 className="max-w-3xl font-medium text-2xl tracking-tight">
              Multi-step support triage agent with human approval
            </h1>
            <p className="max-w-3xl text-muted-foreground text-sm/relaxed">
              This slice turns the official AI SDK tool-calling and loop-control
              recipes into an inspectable support workflow: independent context
              lookups, a dependent SLA decision, a human approval checkpoint,
              and a bounded agent loop.
            </p>
          </div>

          <div className="flex flex-wrap items-center gap-2">
            <Badge variant="outline">{runtimeState.statusLabel}</Badge>
            <Badge variant="outline">{runtimeState.chatModel}</Badge>
          </div>
        </header>

        <div className="lg:h-svh">
          <LoopAgentWorkspace
            chatModel={runtimeState.chatModel}
            isChatAvailable={runtimeState.isChatAvailable}
            nodeVersion={runtimeState.nodeVersion}
            setupMessage={runtimeState.setupMessage}
            triage={triage}
          />
        </div>
      </div>
    </main>
  );
}

"use client";

import { Chat } from "@ai-sdk/react";
import {
  ArrowClockwiseIcon,
  CheckCircleIcon,
  GitBranchIcon,
  StopIcon,
  WrenchIcon,
  XCircleIcon,
} from "@phosphor-icons/react";
import {
  ChainOfThought,
  ChainOfThoughtContent,
  ChainOfThoughtHeader,
  ChainOfThoughtSearchResult,
  ChainOfThoughtSearchResults,
  ChainOfThoughtStep,
} from "@/components/ai-elements/chain-of-thought";
import {
  Confirmation,
  ConfirmationAccepted,
  ConfirmationAction,
  ConfirmationActions,
  ConfirmationRejected,
  ConfirmationRequest,
  ConfirmationTitle,
} from "@/components/ai-elements/confirmation";
import {
  Conversation,
  ConversationContent,
  ConversationEmptyState,
  ConversationScrollButton,
} from "@/components/ai-elements/conversation";
import {
  Message,
  MessageContent,
  MessageResponse,
} from "@/components/ai-elements/message";
import {
  PromptInput,
  PromptInputBody,
  PromptInputFooter,
  PromptInputSubmit,
  PromptInputTextarea,
} from "@/components/ai-elements/prompt-input";
import {
  Reasoning,
  ReasoningContent,
  ReasoningTrigger,
} from "@/components/ai-elements/reasoning";
import { Shimmer } from "@/components/ai-elements/shimmer";
import {
  Tool,
  ToolContent,
  ToolHeader,
  ToolInput,
  ToolOutput,
  type ToolPart,
} from "@/components/ai-elements/tool";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import {
  type ChatAddToolApproveResponseFunction,
  isReasoningUIPart,
  isToolUIPart,
  type UIMessage,
} from "ai";
import { type ReactNode, useMemo } from "react";

import type { SupportTriageResult } from "@/lib/loop-agent/support-triage";
import { useLoopAgentChat } from "./use-loop-agent-chat";

function getTextContent(message: UIMessage) {
  return message.parts
    .filter((part) => part.type === "text")
    .map((part) => part.text)
    .join("\n");
}

function getToolParts(message: UIMessage) {
  return message.parts.filter(isToolUIPart);
}

function getReasoningText(message: UIMessage) {
  return message.parts
    .filter(isReasoningUIPart)
    .map((part) => part.text)
    .join("\n\n");
}

function getToolName(part: ToolPart) {
  return part.type === "dynamic-tool"
    ? part.toolName
    : part.type.split("-").slice(1).join("-");
}

function getBatchStatus(toolNames: string[], toolParts: ToolPart[]) {
  const batchParts = toolParts.filter((part) =>
    toolNames.includes(getToolName(part))
  );

  if (batchParts.length === 0) {
    return "pending" as const;
  }

  const isComplete = batchParts.every(
    (part) =>
      part.state === "output-available" || part.state === "output-denied"
  );

  if (isComplete) {
    return "complete" as const;
  }

  return "active" as const;
}

function getBatchDescription(
  batch: SupportTriageResult["toolBatches"][number],
  triage: SupportTriageResult
) {
  if (batch.tools.includes("requestHumanApproval")) {
    return `Requests human approval before escalating ${triage.caseId}.`;
  }

  if (batch.execution === "parallel") {
    return `Checks account context in parallel before the SLA decision for ${triage.caseId}.`;
  }

  return `Uses the completed account context to assess SLA risk for ${triage.caseId}.`;
}

interface ApprovalToolInput {
  action?: string;
  caseId?: string;
  customerName?: string;
  customerUpdate?: string;
  internalHandoff?: string;
  priority?: string;
  rationale?: string[];
}

function getApprovalToolInput(part: ToolPart): ApprovalToolInput {
  if (
    typeof part.input !== "object" ||
    part.input === null ||
    Array.isArray(part.input)
  ) {
    return {};
  }

  return part.input as ApprovalToolInput;
}

interface HumanApprovalConfirmationProps {
  onApprovalResponse: ChatAddToolApproveResponseFunction;
  part: ToolPart;
  triage: SupportTriageResult;
}

function HumanApprovalConfirmation({
  onApprovalResponse,
  part,
  triage,
}: HumanApprovalConfirmationProps) {
  const approval = part.approval;

  if (!approval) {
    return null;
  }

  const input = getApprovalToolInput(part);
  const target = input.customerName
    ? `${input.customerName} / ${input.caseId ?? triage.caseId}`
    : (input.caseId ?? triage.caseId);
  const action = input.action ?? triage.recommendation.action;
  const priority = input.priority ?? triage.recommendation.priority;

  return (
    <Confirmation
      approval={approval}
      className="border-amber-500/30 bg-amber-500/5"
      state={part.state}
    >
      <ConfirmationTitle>Human approval checkpoint</ConfirmationTitle>
      <ConfirmationRequest>
        <div className="space-y-2 text-sm">
          <p>
            Approve {priority} priority {action} for {target}?
          </p>
          {input.customerUpdate ? (
            <p className="text-muted-foreground">{input.customerUpdate}</p>
          ) : null}
          {input.rationale?.length ? (
            <ul className="list-disc space-y-1 pl-5 text-muted-foreground">
              {input.rationale.map((reason) => (
                <li key={reason}>{reason}</li>
              ))}
            </ul>
          ) : null}
        </div>
      </ConfirmationRequest>
      <ConfirmationAccepted>
        <CheckCircleIcon className="size-4" />
        <span>Approved. The agent can execute the escalation handoff.</span>
      </ConfirmationAccepted>
      <ConfirmationRejected>
        <XCircleIcon className="size-4" />
        <span>Rejected. The agent will continue without escalating.</span>
      </ConfirmationRejected>
      <ConfirmationActions>
        <ConfirmationAction
          onClick={() =>
            onApprovalResponse({
              approved: false,
              id: approval.id,
              reason: "Reviewer rejected the support escalation.",
            })
          }
          variant="outline"
        >
          <XCircleIcon className="size-3.5" />
          Reject
        </ConfirmationAction>
        <ConfirmationAction
          onClick={() =>
            onApprovalResponse({
              approved: true,
              id: approval.id,
              reason: "Reviewer approved the support escalation.",
            })
          }
        >
          <CheckCircleIcon className="size-3.5" />
          Approve
        </ConfirmationAction>
      </ConfirmationActions>
    </Confirmation>
  );
}

export interface LoopAgentWorkspaceProps {
  chatModel: string;
  isChatAvailable: boolean;
  nodeVersion: string;
  setupMessage: string | null;
  triage: SupportTriageResult;
}

interface AssistantTraceProps {
  isLastMessage: boolean;
  isStreaming: boolean;
  message: UIMessage;
  onApprovalResponse: ChatAddToolApproveResponseFunction;
  triage: SupportTriageResult;
}

function AssistantTrace({
  isLastMessage,
  isStreaming,
  message,
  onApprovalResponse,
  triage,
}: AssistantTraceProps) {
  const text = getTextContent(message);
  const reasoningText = getReasoningText(message);
  const toolParts = getToolParts(message);
  const hasReasoning = reasoningText.length > 0;
  const hasText = text.length > 0;
  const lastPart = message.parts.at(-1);
  const isReasoningStreaming =
    isLastMessage && isStreaming && lastPart?.type === "reasoning";
  const showBodyThinking =
    isLastMessage && isStreaming && !hasReasoning && !hasText;
  let bodyContent: ReactNode = null;

  if (hasText) {
    bodyContent = <MessageResponse>{text}</MessageResponse>;
  } else if (showBodyThinking) {
    bodyContent = <Shimmer className="text-sm">Thinking...</Shimmer>;
  }

  return (
    <>
      {hasReasoning ? (
        <Reasoning className="w-full" isStreaming={isReasoningStreaming}>
          <ReasoningTrigger />
          <ReasoningContent>{reasoningText}</ReasoningContent>
        </Reasoning>
      ) : null}

      {toolParts.length > 0 ? (
        <ChainOfThought
          className="rounded-md border border-foreground/10 bg-muted/20 px-3 py-3"
          defaultOpen
        >
          <ChainOfThoughtHeader>Verification steps</ChainOfThoughtHeader>
          <ChainOfThoughtContent>
            {triage.toolBatches.map((batch) => (
              <ChainOfThoughtStep
                description={getBatchDescription(batch, triage)}
                key={batch.label}
                label={batch.label}
                status={getBatchStatus(batch.tools, toolParts)}
              >
                <ChainOfThoughtSearchResults>
                  {batch.tools.map((toolName) => (
                    <ChainOfThoughtSearchResult key={toolName}>
                      {toolName}
                    </ChainOfThoughtSearchResult>
                  ))}
                </ChainOfThoughtSearchResults>
              </ChainOfThoughtStep>
            ))}

            <ChainOfThoughtStep
              description={`${triage.recommendation.priority} priority ${triage.recommendation.action} for ${triage.caseId}.`}
              label="Prepare recommendation"
              status={text ? "complete" : "active"}
            />
          </ChainOfThoughtContent>
        </ChainOfThought>
      ) : null}

      {toolParts.map((part) => (
        <div className="space-y-3" key={part.toolCallId}>
          <HumanApprovalConfirmation
            onApprovalResponse={onApprovalResponse}
            part={part}
            triage={triage}
          />
          <Tool>
            {part.type === "dynamic-tool" ? (
              <ToolHeader
                state={part.state}
                title="Support Triage Tool"
                toolName={part.toolName}
                type={part.type}
              />
            ) : (
              <ToolHeader
                state={part.state}
                title="Support Triage Tool"
                type={part.type}
              />
            )}
            <ToolContent>
              {part.input ? <ToolInput input={part.input} /> : null}
              <ToolOutput errorText={part.errorText} output={part.output} />
            </ToolContent>
          </Tool>
        </div>
      ))}

      {bodyContent}
    </>
  );
}

export function LoopAgentWorkspace({
  chatModel,
  isChatAvailable,
  nodeVersion,
  setupMessage,
  triage,
}: LoopAgentWorkspaceProps) {
  const {
    addToolApprovalResponse,
    error,
    hasMessages,
    isBusy,
    messages,
    regenerate,
    sendMessage,
    status,
    stop,
  } = useLoopAgentChat();
  const samplePrompts = useMemo(
    () => [
      `Triage ${triage.caseId} and explain the tool sequence.`,
      `Triage ${triage.caseId} and show which lookups ran in parallel before the SLA decision.`,
      `Triage ${triage.caseId}, request human approval before escalation, then finalize.`,
    ],
    [triage.caseId]
  );

  return (
    <div className="grid min-h-[70svh] gap-4 lg:h-full lg:min-h-0 lg:grid-cols-[minmax(0,1fr)_22rem]">
      <section className="flex min-h-[70svh] flex-col border border-foreground/10 bg-background lg:h-full lg:min-h-0">
        {isChatAvailable ? null : (
          <div className="border-foreground/10 border-b px-4 py-3 text-muted-foreground text-xs/relaxed">
            {setupMessage}
          </div>
        )}

        {error ? (
          <div className="border-foreground/10 border-b px-4 py-3 text-destructive text-xs/relaxed">
            {error.message}
          </div>
        ) : null}

        <Conversation className="min-h-0">
          <ConversationContent className="mx-auto flex w-full max-w-3xl flex-1 gap-6 px-4 py-6">
            {hasMessages ? (
              messages.map((message, index) => (
                <Message from={message.role} key={message.id}>
                  <MessageContent
                    className={cn(
                      "space-y-4",
                      message.role === "assistant" ? "max-w-3xl" : "max-w-2xl"
                    )}
                  >
                    {message.role === "assistant" ? (
                      <AssistantTrace
                        isLastMessage={index === messages.length - 1}
                        isStreaming={isBusy}
                        message={message}
                        onApprovalResponse={addToolApprovalResponse}
                        triage={triage}
                      />
                    ) : (
                      <MessageResponse>
                        {getTextContent(message)}
                      </MessageResponse>
                    )}
                  </MessageContent>
                </Message>
              ))
            ) : (
              <ConversationEmptyState
                description="Ask the agent to triage the default support case and inspect which tools run before the final recommendation."
                icon={<GitBranchIcon className="size-5" />}
                title="Support triage loop is ready"
              />
            )}
          </ConversationContent>
          <ConversationScrollButton />
        </Conversation>

        <div className="border-foreground/10 border-t px-4 py-4">
          <div className="mx-auto w-full max-w-3xl">
            <PromptInput onSubmit={({ text }) => sendMessage({ text })}>
              <PromptInputBody>
                <PromptInputTextarea
                  disabled={!isChatAvailable || isBusy}
                  placeholder="Ask the agent to triage the default support case."
                />
              </PromptInputBody>
              <PromptInputFooter className="flex items-center justify-between gap-3 border-foreground/10 border-t px-3 py-3">
                <div className="flex flex-wrap items-center gap-2">
                  <Badge variant="outline">ToolLoopAgent</Badge>
                  <Badge variant="outline">Tools</Badge>
                  <Badge variant="outline">Human approval</Badge>
                  <Badge variant="outline">{chatModel}</Badge>
                </div>
                <div className="flex items-center gap-2">
                  {isBusy ? (
                    <Button
                      onClick={stop}
                      size="sm"
                      type="button"
                      variant="outline"
                    >
                      <StopIcon className="size-3.5" />
                      Stop
                    </Button>
                  ) : null}
                  {hasMessages ? (
                    <Button
                      onClick={() => regenerate()}
                      size="sm"
                      type="button"
                      variant="outline"
                    >
                      <ArrowClockwiseIcon className="size-3.5" />
                      Retry
                    </Button>
                  ) : null}
                  <PromptInputSubmit
                    disabled={!isChatAvailable}
                    status={status}
                  />
                </div>
              </PromptInputFooter>
            </PromptInput>

            {hasMessages ? null : (
              <div className="mt-3 flex flex-wrap gap-2">
                {samplePrompts.map((prompt) => (
                  <Button
                    key={prompt}
                    onClick={() => sendMessage({ text: prompt })}
                    size="sm"
                    type="button"
                    variant="outline"
                  >
                    <WrenchIcon className="size-3.5" />
                    {prompt}
                  </Button>
                ))}
              </div>
            )}
          </div>
        </div>
      </section>

      <aside className="border border-foreground/10 bg-background p-4 lg:min-h-0 lg:overflow-y-auto">
        <div className="space-y-5">
          <div>
            <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
              Runtime
            </p>
            <p className="mt-1 font-medium text-sm">{nodeVersion}</p>
          </div>

          <div>
            <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
              Active case
            </p>
            <p className="mt-1 font-medium text-sm">{triage.caseId}</p>
            <p className="mt-1 text-muted-foreground text-sm">
              {triage.ticket.title}
            </p>
          </div>

          <div className="grid gap-2">
            <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
              Tool plan
            </p>
            {triage.toolBatches.map((batch) => (
              <div
                className="border border-foreground/10 p-3"
                key={batch.label}
              >
                <div className="flex items-center justify-between gap-3">
                  <p className="font-medium text-sm">{batch.label}</p>
                  <Badge variant="outline">{batch.execution}</Badge>
                </div>
                <div className="mt-2 flex flex-wrap gap-1.5">
                  {batch.tools.map((toolName) => (
                    <Badge key={toolName} variant="secondary">
                      {toolName}
                    </Badge>
                  ))}
                </div>
              </div>
            ))}
          </div>

          <div>
            <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
              Recommendation
            </p>
            <p className="mt-1 font-medium text-sm">
              {triage.recommendation.action} / {triage.recommendation.priority}
            </p>
            <p className="mt-1 text-muted-foreground text-sm">
              {triage.risk.reason}
            </p>
          </div>
        </div>
      </aside>
    </div>
  );
}

"use client";

import { Chat, useChat } from "@ai-sdk/react";
import {
  DefaultChatTransport,
  lastAssistantMessageIsCompleteWithApprovalResponses,
} from "ai";
import { useState } from "react";

export function useLoopAgentChat() {
  const [chat] = useState(
    () =>
      new Chat({
        sendAutomaticallyWhen:
          lastAssistantMessageIsCompleteWithApprovalResponses,
        transport: new DefaultChatTransport({
          api: "/api/demos/loop-agent",
        }),
      })
  );
  const controller = useChat({ chat });
  const hasMessages = controller.messages.length > 0;
  const isBusy =
    controller.status === "submitted" || controller.status === "streaming";

  return {
    ...controller,
    chat,
    hasMessages,
    isBusy,
  };
}

"use client";

import { CornerDownLeftIcon, LoaderCircleIcon, SquareIcon } from "lucide-react";
import type {
  ComponentProps,
  FormEvent,
  HTMLAttributes,
  ReactNode,
  TextareaHTMLAttributes,
} from "react";
import {
  createContext,
  useCallback,
  useContext,
  useMemo,
  useState,
} from "react";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { cn } from "@/lib/utils";

type PromptStatus = "error" | "ready" | "streaming" | "submitted";

interface PromptInputContextValue {
  setText: (text: string) => void;
  text: string;
}

interface PromptInputMessage {
  text: string;
}

interface PromptInputProps
  extends Omit<HTMLAttributes<HTMLFormElement>, "onSubmit"> {
  children: ReactNode;
  onSubmit: (
    message: PromptInputMessage,
    event: FormEvent<HTMLFormElement>
  ) => void | Promise<void>;
}

interface PromptInputSubmitProps
  extends Omit<ComponentProps<typeof Button>, "children" | "type"> {
  onStop?: () => void;
  status?: PromptStatus;
}

type PromptInputClickEvent = Parameters<
  Exclude<ComponentProps<typeof Button>["onClick"], undefined>
>[0];

const PromptInputContext = createContext<PromptInputContextValue | null>(null);

function usePromptInputContext() {
  const context = useContext(PromptInputContext);

  if (!context) {
    throw new Error(
      "PromptInput components must be used inside <PromptInput>."
    );
  }

  return context;
}

export function PromptInput({
  children,
  className,
  onSubmit,
  ...props
}: PromptInputProps) {
  const [text, setText] = useState("");

  const contextValue = useMemo(
    () => ({
      setText,
      text,
    }),
    [text]
  );

  const handleSubmit = useCallback(
    async (event: FormEvent<HTMLFormElement>) => {
      event.preventDefault();

      const nextText = text.trim();
      if (!nextText) {
        return;
      }

      const result = onSubmit({ text: nextText }, event);

      try {
        await result;
        setText("");
      } catch {
        // Keep the text for retry after a failed submit.
      }
    },
    [onSubmit, text]
  );

  return (
    <PromptInputContext.Provider value={contextValue}>
      <form
        className={cn("w-full", className)}
        onSubmit={handleSubmit}
        {...props}
      >
        {children}
      </form>
    </PromptInputContext.Provider>
  );
}

export function PromptInputBody({
  className,
  ...props
}: HTMLAttributes<HTMLDivElement>) {
  return <div className={cn("grid gap-3", className)} {...props} />;
}

export function PromptInputFooter({
  className,
  ...props
}: HTMLAttributes<HTMLDivElement>) {
  return <div className={cn(className)} {...props} />;
}

export function PromptInputTextarea({
  className,
  disabled,
  onChange,
  ...props
}: TextareaHTMLAttributes<HTMLTextAreaElement>) {
  const context = usePromptInputContext();

  return (
    <Textarea
      className={cn("min-h-16 resize-none", className)}
      disabled={disabled}
      onChange={(event) => {
        context.setText(event.currentTarget.value);
        onChange?.(event);
      }}
      value={context.text}
      {...props}
    />
  );
}

export function PromptInputSubmit({
  className,
  disabled,
  onClick,
  onStop,
  size = "icon",
  status = "ready",
  variant = "default",
  ...props
}: PromptInputSubmitProps) {
  const { text } = usePromptInputContext();
  const isBusy = status === "submitted" || status === "streaming";
  const isDisabled = Boolean(disabled) || (!isBusy && text.trim().length === 0);

  let icon = <CornerDownLeftIcon className="size-4" />;

  if (status === "submitted") {
    icon = <LoaderCircleIcon className="size-4 animate-spin" />;
  } else if (status === "streaming") {
    icon = <SquareIcon className="size-4" />;
  }

  return (
    <Button
      aria-label={isBusy ? "Stop" : "Submit"}
      className={cn(className)}
      disabled={isDisabled}
      onClick={(event: PromptInputClickEvent) => {
        if (isBusy && onStop) {
          event.preventDefault();
          onStop();
          return;
        }

        onClick?.(event);
      }}
      size={size}
      type={isBusy && onStop ? "button" : "submit"}
      variant={variant}
      {...props}
    >
      {icon}
    </Button>
  );
}

import {
  createAgentUIStreamResponse,
  stepCountIs,
  ToolLoopAgent,
  tool,
  type UIMessage,
} from "ai";
import { z } from "zod";

import {
  LOOP_AGENT_PROVIDER_OPTIONS,
  resolveLoopAgentChatModel,
} from "./model";
import {
  createLoopAgentGateway,
  getLoopAgentEnv,
  type LoopAgentEnv,
} from "./env";
import {
  buildSupportEscalationApprovalRequest,
  recordSupportEscalationApproval,
  runSupportTriageLoop,
} from "./support-triage";

const loopAgentInstructions = [
  "You are the loop-agent demo for a support operations team.",
  "Triage support tickets by using tools before making a recommendation.",
  "For questions about the default case, tool sequence, parallel lookups, SLA decision, approval flow, or next support action, use the tools before answering.",
  "Do not answer those workflow questions from the instructions alone.",
  "Start by gathering independent account context, recent tickets, and entitlement information.",
  "Then calculate SLA risk before giving the final action, priority, and rationale.",
  "If the SLA recommendation is a high-priority escalation, call requestHumanApproval with the approvalRequest returned by calculateSlaRisk before the final answer.",
  "If approval is denied, do not retry the approval tool; explain that the escalation was not performed.",
  "Keep the final answer concise and make the tool sequence easy for an engineer to inspect.",
].join(" ");

function createSupportTriageTools() {
  return {
    calculateSlaRisk: tool({
      description:
        "Calculate the SLA risk and recommendation for the active support case after account context is known.",
      inputSchema: z.object({
        caseId: z.string().describe("The support case identifier to triage."),
      }),
      execute: () => {
        const triage = runSupportTriageLoop();

        return {
          approvalRequest: buildSupportEscalationApprovalRequest(triage),
          recommendation: triage.recommendation,
          risk: triage.risk,
        };
      },
    }),
    checkEntitlement: tool({
      description:
        "Check whether the customer is entitled to priority support and escalation.",
      inputSchema: z.object({
        customerId: z
          .string()
          .describe("The customer identifier from the support ticket."),
      }),
      execute: () => {
        const triage = runSupportTriageLoop();

        return {
          plan: triage.customer.plan,
          prioritySupport: triage.customer.plan === "Enterprise",
          supportChannels: ["chat", "email", "priority escalation"],
        };
      },
    }),
    getCustomerProfile: tool({
      description:
        "Fetch the customer profile, plan, and account context for a support ticket.",
      inputSchema: z.object({
        customerId: z
          .string()
          .describe("The customer identifier from the support ticket."),
      }),
      execute: () => {
        const triage = runSupportTriageLoop();

        return triage.customer;
      },
    }),
    listRecentTickets: tool({
      description:
        "List recent support tickets so the agent can detect repeated incidents.",
      inputSchema: z.object({
        customerId: z
          .string()
          .describe("The customer identifier from the support ticket."),
      }),
      execute: () => {
        const triage = runSupportTriageLoop();

        return {
          activeTicket: triage.ticket,
          recentTickets: [
            {
              id: "TIC-7712",
              status: "resolved",
              title: "Scheduled export job exceeded retry budget",
            },
          ],
        };
      },
    }),
    requestHumanApproval: tool({
      description:
        "Request human approval before performing the recommended high-priority support escalation.",
      inputSchema: z.object({
        action: z.literal("escalate").describe("The approved action to take."),
        caseId: z.string().describe("The support case identifier."),
        customerName: z.string().describe("The customer name."),
        customerUpdate: z
          .string()
          .describe("The message the support team will send to the customer."),
        internalHandoff: z
          .string()
          .describe("The internal escalation handoff note."),
        priority: z.literal("high").describe("The escalation priority."),
        rationale: z
          .array(z.string())
          .min(1)
          .describe("The reasons the escalation needs human approval."),
      }),
      needsApproval: true,
      execute: (approvalRequest) =>
        recordSupportEscalationApproval(approvalRequest),
    }),
  };
}

export function streamLoopAgent(
  messages: UIMessage[],
  env: LoopAgentEnv = getLoopAgentEnv()
) {
  const gateway = createLoopAgentGateway(env);
  const chatModel = resolveLoopAgentChatModel(env);
  const agent = new ToolLoopAgent({
    instructions: loopAgentInstructions,
    model: gateway(chatModel),
    providerOptions: LOOP_AGENT_PROVIDER_OPTIONS,
    stopWhen: stepCountIs(6),
    tools: createSupportTriageTools(),
  });

  return createAgentUIStreamResponse({
    agent,
    sendReasoning: true,
    uiMessages: messages,
  });
}

import { createGateway } from "ai";
const DEFAULT_GATEWAY_BASE_URL = "https://ai-gateway.vercel.sh/v3/ai";
export const DEFAULT_LOOP_AGENT_CHAT_MODEL = "openai/gpt-5-mini";
const MINIMUM_NODE_VERSION = "22.13.0";
const nodeVersionPattern = /^v?(\d+)\.(\d+)\.(\d+)(?:[-+].*)?$/;

interface ParsedNodeVersion {
  major: number;
  minor: number;
  patch: number;
}

export type LoopAgentEnv = Record<string, string | undefined>;

export interface LoopAgentConfig {
  apiKey: string;
  baseURL: string;
  chatModel: string;
}

export interface LoopAgentSetupState {
  config: Omit<LoopAgentConfig, "apiKey">;
  isReady: boolean;
  issues: string[];
  nodeVersion: string;
}

function parseNodeVersion(version: string): ParsedNodeVersion {
  const match = nodeVersionPattern.exec(version);
  const major = Number(match?.[1]);
  const minor = Number(match?.[2]);
  const patch = Number(match?.[3]);

  if (![major, minor, patch].every(Number.isInteger)) {
    throw new Error(`Unable to parse Node.js version: "${version}".`);
  }

  return { major, minor, patch };
}

function compareNodeVersions(
  left: ParsedNodeVersion,
  right: ParsedNodeVersion
) {
  if (left.major !== right.major) {
    return left.major - right.major;
  }

  if (left.minor !== right.minor) {
    return left.minor - right.minor;
  }

  return left.patch - right.patch;
}

function assertSupportedNodeRuntime(version = process.version) {
  const parsedVersion = parseNodeVersion(version);
  const minimumVersion = parseNodeVersion(MINIMUM_NODE_VERSION);

  if (compareNodeVersions(parsedVersion, minimumVersion) < 0) {
    throw new Error(
      `Node.js ${version} is unsupported. This demo workspace requires Node.js >=${MINIMUM_NODE_VERSION}.`
    );
  }
}

export function getLoopAgentEnv(): LoopAgentEnv {
  // biome-ignore lint/style/noProcessEnv: Registry source installs into consumer apps without this repo's env wrapper.
  return process.env;
}

function readRequiredEnv(env: LoopAgentEnv, name: keyof LoopAgentEnv) {
  const value = env[name];

  if (!value) {
    throw new Error(
      `Missing ${name}. Add it to .env.local before using the loop agent.`
    );
  }

  return value;
}

function resolveLoopAgentEnv(env: LoopAgentEnv = getLoopAgentEnv()) {
  return {
    apiKey: env.AI_GATEWAY_API_KEY,
    baseURL: env.AI_GATEWAY_BASE_URL || DEFAULT_GATEWAY_BASE_URL,
    chatModel: env.AI_GATEWAY_CHAT_MODEL || DEFAULT_LOOP_AGENT_CHAT_MODEL,
  };
}

export function getLoopAgentConfig(
  env: LoopAgentEnv = getLoopAgentEnv()
): LoopAgentConfig {
  assertSupportedNodeRuntime();
  const resolvedEnv = resolveLoopAgentEnv(env);

  return {
    apiKey: readRequiredEnv(env, "AI_GATEWAY_API_KEY"),
    baseURL: resolvedEnv.baseURL,
    chatModel: resolvedEnv.chatModel,
  };
}

export function getLoopAgentSetupState(
  env: LoopAgentEnv = getLoopAgentEnv()
): LoopAgentSetupState {
  const issues: string[] = [];
  const resolvedEnv = resolveLoopAgentEnv(env);

  try {
    assertSupportedNodeRuntime();
  } catch (error) {
    issues.push(
      error instanceof Error ? error.message : "Unsupported Node.js runtime."
    );
  }

  if (!resolvedEnv.apiKey) {
    issues.push(
      "AI_GATEWAY_API_KEY is missing. The demo can render, but chat requests will fail until it is configured."
    );
  }

  return {
    config: {
      baseURL: resolvedEnv.baseURL,
      chatModel: resolvedEnv.chatModel,
    },
    isReady: issues.length === 0,
    issues,
    nodeVersion: process.version,
  };
}

export function createLoopAgentGateway(
  env: LoopAgentEnv = getLoopAgentEnv()
) {
  const { apiKey, baseURL } = getLoopAgentConfig(env);

  return createGateway({
    apiKey,
    baseURL,
  });
}

